1175   ID.AddInteger(scTruncate);
1176   ID.AddPointer(Op);
1177   ID.AddPointer(Ty);
1178   void *IP = nullptr;
1179   if (const SCEV *S = UniqueSCEVs.FindNodeOrInsertPos(ID, IP)) return S;
